static void cb_back(lv_event_t *e)   { (void)e; on_spotify_back(); }
static void cb_play(lv_event_t *e)
{
    (void)e; sp.playing = !sp.playing;
    lv_label_set_text(sp.lbl_play_icon, sp.playing ? LV_SYMBOL_PAUSE : LV_SYMBOL_PLAY);
    on_spotify_play(sp.playing);
}
static void cb_prev(lv_event_t *e)
{
    (void)e;
    if (sp.elapsed_sec > 5) { sp.elapsed_sec = 0; return; }
    int n = sp.shuffle ? (lv_rand(0,PL_COUNT*99)%PL_COUNT) : (sp.active_pl-1+PL_COUNT)%PL_COUNT;
    set_active_playlist(n); on_spotify_prev();
}
static void cb_next(lv_event_t *e)
{
    (void)e;
    int n = sp.shuffle ? (lv_rand(0,PL_COUNT*99)%PL_COUNT) : (sp.active_pl+1)%PL_COUNT;
    set_active_playlist(n); on_spotify_next();
}
static void cb_playlist(lv_event_t *e)
{
    int idx = (int)(intptr_t)lv_event_get_user_data(e);
    set_active_playlist(idx); sp.playing = true;
    lv_label_set_text(sp.lbl_play_icon, LV_SYMBOL_PAUSE);
    on_spotify_playlist(idx);
}
static void cb_shuffle(lv_event_t *e)
{
    (void)e; sp.shuffle = !sp.shuffle;
    lv_obj_set_style_text_color(sp.lbl_shuffle, sp.shuffle ? C_ACCENT : C_DIM, 0);
    lv_obj_set_style_border_color(sp.btn_shuffle, sp.shuffle ? C_PL_BDR_A : C_BTN_BDR, 0);
    on_spotify_shuffle(sp.shuffle);
}
static void cb_repeat(lv_event_t *e)
{
    (void)e; sp.repeat = !sp.repeat;
    lv_obj_set_style_text_color(sp.lbl_repeat, sp.repeat ? C_ACCENT : C_DIM, 0);
    lv_obj_set_style_border_color(sp.btn_repeat, sp.repeat ? C_PL_BDR_A : C_BTN_BDR, 0);
    on_spotify_repeat(sp.repeat);
}

